# Pings the hub's public liveness probe + root every 10 min so the serverless
# function's idle timer never trips (Vercel sleeps idle functions ~15 min).
# Free; no plan limits. Run manually via workflow_dispatch to verify.
# NOTE: warms the entry/health functions; per-route cold starts on other
# endpoints are unavoidable on Hobby (Vercel Pro Fluid Compute helps). This is
# a latency patch, NOT a data-durability fix (data still needs Turso).
on:
  schedule:
    - cron: "*/10 * * * *"
  workflow_dispatch:

jobs:
  ping:
    runs-on: ubuntu-latest
    steps:
      - name: Ping hub
        run: |
          for u in \
            https://marketing-hub-roan.vercel.app/api/health \
            https://marketing-hub-roan.vercel.app/ ; do
            code=$(curl -s -o /dev/null -w "%{http_code}" --max-time 25 "$u" || echo "ERR")
            echo "$code  $u"
          done---GITHUB---
